import { Link, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import toast from 'react-hot-toast';

export default function Navbar() {
  const { user, logout, isAdmin } = useAuth();
  const { count } = useCart();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    toast.success('Sesión cerrada');
    navigate('/');
  };

  return (
    <nav className="navbar">
      <div className="container">
        <Link to="/" className="navbar-brand">🛍️ ShopApp</Link>
        <ul className="navbar-nav">
          <li><NavLink to="/catalog">Catálogo</NavLink></li>
          {user ? (
            <>
              <li>
                <NavLink to="/cart" className="cart-badge">
                  🛒 Carrito {count > 0 && <span>{count}</span>}
                </NavLink>
              </li>
              <li><NavLink to="/profile">Mi cuenta</NavLink></li>
              {isAdmin && <li><NavLink to="/admin">Admin</NavLink></li>}
              <li>
                <button className="btn btn-outline btn-sm" onClick={handleLogout}>Salir</button>
              </li>
            </>
          ) : (
            <>
              <li><NavLink to="/login">Iniciar sesión</NavLink></li>
              <li><Link to="/register" className="btn btn-primary btn-sm">Registrarse</Link></li>
            </>
          )}
        </ul>
      </div>
    </nav>
  );
}
